var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"하하, 다들 날 이렇게 그리워할 줄은 몰랐는데.","JPN":"ハハ、みんながそこまで私のことを想ってたとはね。","ENG":"Whoa, I didn't think you'd welcome me like this.","TWN":"哈哈，沒想到大家都這麼想我啊。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_LAUGH"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"이러니까 내가 좀 미안해지잖아?","JPN":"これじゃ、ちょっと申し訳ない気持ちにもなるなぁ。","ENG":"Now you're making me feel sorry.","TWN":"這樣我不就有點過意不去了嗎？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"너...... 지난번엔 못 보던 걸 들고 온 것 같은데.","JPN":"あんた……見覚えのないものを持っているようだけど。","ENG":"You... You didn't have that thing with you before.","TWN":"妳……好像帶了些我們上次沒見過的東西。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그 창은 또 뭐야?","JPN":"その槍は何？","ENG":"What's that spear?","TWN":"那把長矛又是什麼？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"아, 이거? 별거 아니야.","JPN":"あ、これのこと？　大したものじゃないよ。","ENG":"Oh, this? It's nothing.","TWN":"啊，這個？沒什麼特別的。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"나라고 언제까지나 평범한 무기나 쓰고 있을 수는 없잖아?","JPN":"いつまでも地味な武器を使い続けるわけにもいかないでしょ？","ENG":"I can't run around wielding boring weapons forever, can I?","TWN":"我總不能一直用那些普通的武器嘛?"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"널 상대하려면 나도 제대로 된 고유무장 하나 정도는 있어야지.","JPN":"あなたを相手にするなら、私もちゃんとした固有武装の一つくらい、持たないとね。","ENG":"How am I supposed to fight you without a proper Unique Gear?","TWN":"想要當妳的對手，我也得有個像樣的專屬裝備啊。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"뭐...... 그래 봐야 리플레이서 퀸이 쓰다 남은 레플리카이긴 하겠지만.","JPN":"まあ……とはいっても、リプレイサー・クイーンが使い古したレプリカだけど。","ENG":"Well, I guess it's one of those replicas that Replacer Queen got bored with, though.","TWN":"不過……是克隆．女皇用剩下的複製品罷了。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"설마...... 구 관리국의 고유무장을 지급받았다고?","JPN":"まさか……旧管理局の固有武装が与えられた？","ENG":"Wait, they gave you a Unique Gear of the Old Administration?","TWN":"難道……妳拿到了舊管理局的專屬裝備？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"말도 안돼...... 그건 리플레이서 간부에게나 제공되는 전략 무기일 텐데......?","JPN":"そんなバカな……それはリプレイサーの幹部級じゃないともらえない戦略武器のはずだけど……？","ENG":"No way... Those are strategic assets only given out to Replacer officers!","TWN":"怎麼可能……那應該是提供給克隆集團幹部的戰略武器才對啊……？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"저, 정말로 리플레이서 놈들과 손을 잡은 거야?","JPN":"ほ、本当にリプレイサーどもと手を組んだのか？","ENG":"A-are you really working with the Replacers?","TWN":"妳、妳真的和克隆集團的傢伙們聯手了嗎？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L16_1","type":"dialog","speaker":"KIMSOBIN_ALT_NULL_NULL","text":{"KOREA":"대, 대장......","JPN":"た、隊長……","ENG":"C-Cap!","TWN":"隊、隊長……"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"WATCHER_REPLACER_NULL_NULL","text":{"KOREA":"침입자를 확인했다!","JPN":"侵入者を確認した！","ENG":"We've spotted an intruder!","TWN":"已確認到侵入者！"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WATCHER_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SOLDIER_REPLACER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"WATCHER_REPLACER_NULL_NULL","text":{"KOREA":"B-6 순찰대를 궤멸시킨 상대와 동일 인물로 판단된다!","JPN":"B-6パトロール隊を壊滅させた相手と同一人物とみられる！","ENG":"It's likely the same individual as the one that annihilated Remote Scout B-6!","TWN":"和擊敗B-6巡邏隊的人是同一人物！"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WATCHER_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SOLDIER_REPLACER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"WATCHER_REPLACER_NULL_NULL","text":{"KOREA":"전 대원, 전투준비!","JPN":"全隊員、戦闘準備せよ！","ENG":"All units, prepare for battle!","TWN":"全體隊伍，準備戰鬥！"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WATCHER_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SOLDIER_REPLACER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"WATCHER_REPLACER_NULL_NULL","text":{"KOREA":"운이 좋군!","JPN":"これは、ツイてるな！","ENG":"You got lucky.","TWN":"運氣不錯嘛！"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WATCHER_REPLACER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"WATCHER_REPLACER_NULL_NULL","text":{"KOREA":"색적 레이더도 사용할 수 없는데 이렇게 빨리 놈들을 찾아내다니.","JPN":"索敵レーダーも使えない状況なのに、こんなに早く奴らを見つけられるとは。","ENG":"It was pure luck that you found them so quickly when you can't even use the search radar.","TWN":"在無法使用雷達系統的情況下，竟然還這麼快就找出了這些傢伙。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WATCHER_REPLACER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"WATCHER_REPLACER_NULL_NULL","text":{"KOREA":"잘했다, 서윤!","JPN":"お手柄だ、シズカ！","ENG":"Good work, Seo Yoon!","TWN":"幹得好，徐芸！"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WATCHER_REPLACER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_HATE"},"C":null,"R":{"char_id":"WATCHER_REPLACER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"WATCHER_REPLACER_NULL_NULL","text":{"KOREA":"하지만 우쭐대진 말도록.","JPN":"だが、あまり調子に乗るなよ。","ENG":"But don't get excited so early.","TWN":"但是不要太得意忘形。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_HATE"},"C":null,"R":{"char_id":"WATCHER_REPLACER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"WATCHER_REPLACER_NULL_NULL","text":{"KOREA":"혹시 놈들을 놓치기라도 하면 모조리 네 책임이라는 건 알고 있겠지?","JPN":"もしも奴らを逃したら、すべてお前の責任だからな？","ENG":"You'll be held responsible if any one of them gets out.","TWN":"要是妳讓那些傢伙逃了，這就全是妳的責任了，妳是知道的吧？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_HATE"},"C":null,"R":{"char_id":"WATCHER_REPLACER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"WATCHER_REPLACER_NULL_NULL","text":{"KOREA":"네 충성심을 의심받고 싶지 않으면 최선을 다해라!","JPN":"お前の忠誠心を疑われたくないなら、最善を尽くせ！","ENG":"Do your best if you don't want your loyalty questioned!","TWN":"如果妳不想害自己的忠誠心受到質疑，就給我全力以赴！"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_HATE"},"C":null,"R":{"char_id":"WATCHER_REPLACER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"......내가 맡는 건 펜릴 소대원뿐이라고 사전에 합의했을 텐데?","JPN":"……私が引き受けるのはフェンリル小隊のみって、事前に合意済みのはずだけど？","ENG":"Wasn't it our deal that I take care of the Fenrir Squad, and nothing more?","TWN":"……我們事前不是說好，我只負責芬里爾小隊的隊員嗎？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WATCHER_REPLACER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"WATCHER_REPLACER_NULL_NULL","text":{"KOREA":"그래? 난 기억이 안 나는데.","JPN":"そうか？　そんな記憶はないんだが。","ENG":"Oh yeah? But I don't remember.","TWN":"是嗎？我不記得了。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WATCHER_REPLACER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WATCHER_REPLACER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"WATCHER_REPLACER_NULL_NULL","text":{"KOREA":"퀸께서 조금 예뻐한다고 해서 뭐라도 된 것처럼 생각한다면 큰 착각이다.","JPN":"クイーンに可愛がられてるからっていい気になるのは大きな間違いだ。","ENG":"Just because Queen favors you doesn't mean you get to forget your place with me.","TWN":"如果妳以為女皇說了幾句好話，我就會對妳比較好，那就大錯特錯了。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WATCHER_REPLACER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"WATCHER_REPLACER_NULL_NULL","text":{"KOREA":"너같이 윗선에 아양이나 떠는 전직 배신자는 쉽게 믿을 수 없지.","JPN":"お前のように上層部にごまをすってばかりの元裏切り者は、簡単には信用できん。","ENG":"A brown-nose traitor like you cannot be trusted so easily.","TWN":"像妳這種諂媚上層，原本是叛徒的人，是不能夠輕易相信的。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WATCHER_REPLACER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"WATCHER_REPLACER_NULL_NULL","text":{"KOREA":"내가 네 감시관이라는 사실을 명심하도록!","JPN":"私がお前の監視官であることを肝に銘じておけよ！","ENG":"Keep in mind that I'm here to watch over you.","TWN":"記住我是妳的督軍。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WATCHER_REPLACER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"WATCHER_REPLACER_NULL_NULL","text":{"KOREA":"내가 시키면 넌 구른다! 그게 규칙이야.","JPN":"私の命令次第でお前は転ぶんだ！　それがルールだからな。","ENG":"When I say get it done, you get it done. That's the rule.","TWN":"我說什麼妳就要照做！這就是規則！"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WATCHER_REPLACER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"WATCHER_REPLACER_NULL_NULL","text":{"KOREA":"진흙탕이건 어디건 말이지!","JPN":"たとえ、それがどこであれ！","ENG":"You don't get to complain about it.","TWN":"不管是上刀山還是下火海！"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WATCHER_REPLACER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"WATCHER_REPLACER_NULL_NULL","text":{"KOREA":"알아 들었나?!","JPN":"わかったか！？","ENG":"Are we clear?","TWN":"聽清楚了嗎？！"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WATCHER_REPLACER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WATCHER_REPLACER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"뭐 그러시다는데...... 너도 들었지?","JPN":"そういうことだけど……あなたも聞いたよね？","ENG":"Well, you heard that.","TWN":"既然這樣……妳也聽到了吧？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"시간 없으니까 빨리 붙어보자고. 유미나.","JPN":"時間もないし、早く勝負しようよ。ヤナギ・ミナ。","ENG":"We don't have much time, so bring it on, Yoo Mina.","TWN":"我沒有時間了，快點來打一場吧，劉米娜。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"아직 늦지 않았어, 서윤.","JPN":"まだ間に合うよ、シズカ。","ENG":"It's not too late yet, Seo Yoon.","TWN":"現在還來得及，徐芸。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"다시 생각해 봐.","JPN":"考え直して。","ENG":"Think again.","TWN":"請妳再好好想想吧。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"......그래?","JPN":"……そう？","ENG":"Think again?","TWN":"……是嗎？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_LAUGH"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"내 생각엔 그런 소릴 하기엔 한참 늦은 것 같은데.","JPN":"そんな話はとっくに終わってると思うけど？","ENG":"I've come too far to give it a second thought.","TWN":"我覺得現在說那種話已經太遲了。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"저 녀석들...... 오직 널 구하기 위해서 그 위험을 무릅쓰고 여기까지 온 거야.","JPN":"あいつら……あんたを助けようと、あんな危険を冒してまでここまできたんだよ。","ENG":"Your teammates... They came all the way here risking their lives, just to save you.","TWN":"那些傢伙……就只為了救妳，冒著生命危險來到這裡。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"네 동료들은 아직 널 믿고 있다고.","JPN":"あんたの仲間はまだあんたのことを信じてるから。","ENG":"They still have faith in you.","TWN":"妳的夥伴都還相信著妳。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"리플레이서 놈들이 네게 뭘 약속했는지는 모르겠지만......","JPN":"リプレイサーどもがあんたに何を約束したかは知らないけど……","ENG":"I don't know what the Replacers promised you,","TWN":"雖然我不知道克隆集團的那些傢伙和妳做了什麼約定……"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그게 정말 네 동료들보다 중요한 거야?","JPN":"それって、本当にあんたの仲間より大事なことなの？","ENG":"but is it really more important than your comrades?","TWN":"但那真的比妳的夥伴更重要嗎？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"시끄러워.","JPN":"うるさいな。","ENG":"Shut up.","TWN":"囉嗦。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"말했었지? 더 이상 약자로 사는 건 지긋지긋하다고.","JPN":"言ったでしょ？　これ以上弱者のままなのはイヤだって。","ENG":"I told you, I'm sick and tired of living a loser's life.","TWN":"我說過了吧？我已經厭倦再像弱者一樣活著了。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"그러니까...... 날 데려가고 싶으면 입이 아니라 힘으로 데려가 봐.","JPN":"だから……私を連れて帰りたいなら言葉じゃなく、力づくでかかってきなさいよ。","ENG":"So... If you want to take me, you'll have to do it with your fists, not your lips.","TWN":"所以……如果妳想要把我帶回去，就別光用說的，憑妳的力量把我帶走吧。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"마침 방해꾼들도 없잖아?","JPN":"ちょうど邪魔者もいないしね？","ENG":"There's nothing to disturb us now.","TWN":"不是正好也沒有人會妨礙我們嗎？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"나도 궁금한걸? 지금의 내가 널 쓰러트릴 수 있을지 말야.","JPN":"私も試してみたいのよ、今の私があなたを倒せるかどうか。","ENG":"I'm kind of curious, you know. I want to know if I'll be able to defeat you.","TWN":"我也很好奇呢，現在的我究竟能不能打敗妳。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"......좋아.","JPN":"……いいよ。","ENG":"Fine.","TWN":"……好。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_FENRIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그렇게까지 말한다면......","JPN":"そこまで言うなら……","ENG":"If you want to go the hard way,","TWN":"既然妳都說到這個份上了……"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_FENRIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"원하는 대로 힘으로 끌고 가 주지!!","JPN":"望みどおり、力ずくで連れて帰る！！","ENG":"so be it.","TWN":"那就如妳所願，用我的力量把妳帶回去！！"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_FENRIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};